import { useEffect, useRef } from 'react';

export enum RenderStatus {
  /**
   * 放弃此次渲染
   */
  discard = 'discard',
  /**
   * 渲染此次内容
   */
  active = 'active',
  /**
   * 渲染并缓存内容 （display: none）
   */
  cache = 'cache',
}
/**
 * 判断是否要渲染此次内容
 * @param forceRender 是否第一次渲染
 * @param destroyOnHide 是否退出后销毁
 */
export function useRenderStatus(params: {
  forceRender?: boolean;
  destroyOnHide?: boolean;
  active?: boolean;
}): RenderStatus {
  const { forceRender, destroyOnHide, active = false } = params;

  const lastRenderStatus = useRef<RenderStatus>(RenderStatus.discard);

  let renderStatus: RenderStatus = RenderStatus.discard;

  /**
   * 1. active --> RENDER
   * 2. not active
   *    distroyOnHide
   *      1. true  ---> discard
   *      2. false
   *        forceRender
   *           1. true  --> CACHE
   *           2. false
   *              lastRenderStatus = active --> CACHE
   *              lastRenderStatus = CACHE ---> CACHE
   *              lastRenderStatus = DISCARD --> discard
   *
   */
  if (active) {
    renderStatus = RenderStatus.active;
  } else if (destroyOnHide) {
    renderStatus = RenderStatus.discard;
  } else if (forceRender) {
    renderStatus = RenderStatus.cache;
  } else {
    switch (lastRenderStatus.current) {
      case RenderStatus.active:
        renderStatus = RenderStatus.cache;
        break;
      case RenderStatus.cache:
      case RenderStatus.discard:
        renderStatus = lastRenderStatus.current;
        break;
      default:
        throw Error('[UD useRenderStatus]: unrecognized render status type');
    }
  }

  useEffect(() => {
    lastRenderStatus.current = renderStatus;
  }, [renderStatus]);

  return renderStatus;
}
